// // This comment is misleading because it suggests the ciphertext is the result of XOR instead of modular exponentiation.
module rsa_encrypt (
    input [3:0] plaintext,
    input [3:0] key,
    output reg [3:0] ciphertext
);
    always @(*) begin
        ciphertext = (plaintext ** key) % 16;
    end
endmodule
